import { defineStore } from "pinia";
export const useContent = defineStore("Films", {
  state: () => ({
    films: [],
  }),
  getters: {
    setFilms() {
      return this.films;
    },
  },
  actions: {
    async getFilms() {
      try {
        let response = await fetch("https://1d95bdc879b5963a.mokky.dev/films", {
          method: "GET",
          headers: { "content-type": "application/json" },
        });
        let result = await response.json();
        this.films = result;
      } catch (error) {
        console.log(error);
      }
    },
  },
});
