<template>
    <div class="popup__wrapper">

        <div class="popup">
            <div class="popup__close" @click="$emit('ClosePopUp', false)">Х</div>
            <h2 class="popup__title">Впиши название фильма </h2>
            <div class="popup__top">
                <inputComponent class="popup__input" @returnValue="(text) => this.filmName = text"
                    :textForPlaceholder="'Название фильма'" :error="this.errorText">
                </inputComponent>
                <div class="popup__btn" @click="findFilm()">
                    <img src="../../assets/img/search-svg.svg" alt="" class="popup__btn-img">
                </div>
            </div>
            <div v-if="this.listOfFindedFilms.length == 0" class="popup__attention">Данная параша работает по
                бесплатному API
                ключу, потому что маленькая инди
                компания Yandex не может позволить себе больше 200 бесплатных запросов(Привет ютубу, где я делал по
                1000+ в день).Так что динамического поиска тут нет, просьба писать название фильма без ошибок на всякий
                пожарный =)</div>
            <div v-else class="popup__films">
                <addMovieCard v-for="item, index in this.listOfFindedFilms.docs" :key="index" :name="item.name"
                    :index="index" :desc="item.description" :year="item.year" @addFilm="(index) => addNewFilm(index)">
                </addMovieCard>
            </div>
        </div>
    </div>
</template>

<script>
import addMovieCard from '../elements/addMovieCard.vue';
import inputComponent from '../elements/inputComponent.vue';

export default {

    data() {
        return {
            filmName: "",
            errorText: "",
            listOfFindedFilms: [],
        }
    },
    components: {
        inputComponent, addMovieCard
    },
    methods: {
        async findFilm() {
            if (this.filmName == "") {
                this.errorText = "Название фильма напиши даун)"
            }
            else {
                try {
                    this.errorText = ""
                    let response = await fetch(`https://api.kinopoisk.dev/v1.4/movie/search?page=1&limit=10&query=${this.filmName}`, {
                        method: "GET",
                        headers: {
                            accept: 'application/json',
                            'X-API-KEY': '0ZGKZ63-NXGMT2M-K6VBGQZ-4Y50733'
                        }
                    })
                    this.listOfFindedFilms = await response.json()
                }
                catch (error) {
                    console.log(error);
                }
            }
        },
        async addNewFilm(index) {
            try {
                await fetch("https://1d95bdc879b5963a.mokky.dev/films", {
                    method: "POST",
                    headers: {
                        'Content-Type': 'application/json;charset=utf-8'
                    },
                    body: JSON.stringify({
                        filmName: this.listOfFindedFilms.docs[index].name,
                        year: this.listOfFindedFilms.docs[index].year,
                        imgPath: this.listOfFindedFilms.docs[index].poster.previewUrl,
                        whoSendIt: JSON.parse(localStorage.getItem("user")).name,
                        status: "Предложенные",
                    })
                })
            }
            catch (error) {
                console.log(error)
            }
        }
    }
}

</script>


<style scoped>
.popup__wrapper {
    position: fixed;
    width: 100%;
    height: 100%;
    top: 0;
    left: 0;
    background-color: rgba(0, 0, 0, 0.8);
    z-index: 5;
}

.popup {
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    width: 960px;
    height: 800px;
    background: #003832;
    padding: 50px 20px;
    border-radius: 20px;
    z-index: 10;
}

.popup__close {
    position: absolute;
    top: 20px;
    right: 30px;
    font-size: 20px;
    color: #fff;
    font-weight: 700;
    cursor: pointer;
}

.popup__title {
    font-size: 32px;
    color: #fff;
    font-weight: 700;

    margin-bottom: 20px;
}

.popup__top {
    position: relative;
}


.popup__btn {
    position: absolute;
    top: 10px;
    right: 15px;
    display: flex;
    border-radius: 5px;
    justify-content: center;
    align-items: center;
    width: 24px;
    aspect-ratio: 1;
    cursor: pointer;
}

.popup__btn-img {
    width: 100%;
    height: 100%;
}

.popup__attention {
    font-size: 14px;
    color: #fff;
    text-align: center;
}

.popup__films {
    max-height: 600px;
    overflow-y: auto;
}
</style>