<template>
    <div class="card__wrapper">
        <img :src="imgPath" alt="filmImg" class="card__img">
        <div class="card__filmName">{{ filmName }} <br> <span style="font-size: 14px;"> {{ year }} года</span></div>
        <div class="card__filmStatus">{{ status }}</div>
        <div class="card__rate" :class="dynamicClass"> {{ allRate }}</div>
    </div>
</template>
<script>
export default {
    data() {
        return {
            allRate: 0,
        }
    },
    props: [
        "filmName", "imgPath", "status", "objRate", "year"
    ],
    methods: {
        caclulateRate() {
            let returnSum = 0;
            let people = 0;
            for (let key in this.objRate) {
                returnSum += this.objRate[key];
                people++
            }
            this.allRate = (returnSum / people).toFixed(1);
        }
    },
    computed: {
        dynamicClass() {
            let des = '';
            if (this.allRate <= 4) {
                des = 'red';
            }
            else if (this.allRate <= 7) {
                des = 'yellow';
            }
            else {
                des = 'green';
            }
            return des;
        }
    },
    created() {
        this.caclulateRate();
    }

}
</script>
<style scoped>
.card__wrapper {
    display: flex;
    flex-direction: column;
    justify-content: space-between;
    flex: 0 0 20%;
    position: relative;
    padding: 20px 15px;
    background: #119686;
    border-radius: 20px;
}

.card__img {
    max-width: 220px;
    height: 300px;
    margin-bottom: 20px;
    border-radius: 20px;
}

.card__filmName {
    display: block;
    width: fit-content;
    font-weight: 700;
    font-size: 24px;
    color: #fff;
}

.card__filmStatus {
    margin-top: 10px;
    display: block;
    width: fit-content;

}


.card__rate {
    color: #fff;

    position: absolute;
    padding: 7px;
    border-radius: 50%;
    bottom: 20px;
    right: 20px;
    font-weight: 700;
    font-size: 14px;
}

.red {
    background: rgb(252, 10, 10);

}

.yellow {
    background: gray;

}

.green {
    background: rgb(2, 175, 2);

}
</style>
