<template>
    <div class="root">
        <popupBlock v-if="isPopUpOpen" @closePopUp="(state) => this.isPopUpOpen = state"></popupBlock>
        <headerBlock @openPopUp="(state) => this.isPopUpOpen = state"></headerBlock>
        <contentBlock></contentBlock>
    </div>
</template>

<script>
import headerBlock from '../blocks/headerBlock.vue';
import contentBlock from '../blocks/contentBlock.vue';
import popupBlock from '../blocks/popupBlock.vue';

import { useContent } from '@/stores/filmsStore.js';
export default {
    data() {
        return {
            isPopUpOpen: false,
        }

    },
    created() {
        this.listOfFilms = useContent();
        this.listOfFilms.getFilms();
    },
    components: {
        headerBlock, contentBlock, popupBlock
    },
}
</script>

